     * Reconstruye el camino más corto desde el origen hasta el destino
     * utilizando el mapa de predecesores
     * @param TreeMap<Vertex, Vertex> pred
     * @param Vertex source
     * @param Vertex destination
     * @return List<Vertex>
     */
    private static List<Vertex> reconstructPath(TreeMap<Vertex, Vertex> pred, Vertex source, Vertex destination) {
        List<Vertex> path = new ArrayList<>();

        // Comenzar desde el destino y retroceder
        for (Vertex current = destination; current != null; current = pred.get(current)) {
            path.add(current);
            if (current.equals(source)) {
                break; // Hemos llegado al origen
            }
        }

        // Invertir el camino para obtener origen -> destino
        Collections.reverse(path);
        return path;
    }
}

public Collection<Vertex> getVertices() {
    return adjacencyMap.keySet();
}

/**
 * Metodo que verifica si dos vertices son adyacentes
 * @param Vertex v1
 * @param Vertex v2
 * @return boolean adyacentes
 */
public boolean adyacentes(Vertex v1, Vertex v2) {
    if (!adjacencyMap.containsKey(v1)) {
        return false;
    }
    return adjacencyMap.get(v1).containsKey(v2);
}

/**
 * Metodo que devuelve el peso entre dos vertices
 * @param Vertex v1
 * @param Vertex v2
 * @return double peso
 */
public double peso(Vertex v1, Vertex v2) {
    if (!adyacentes(v1, v2)) {
        return Double.POSITIVE_INFINITY;
    }
    return adjacencyMap.get(v1).get(v2);
}

/**
 * Metodo que devuelve el peso entre dos vertices
 * @param Vertex v1
 * @param Vertex v2
 * @return double
 */
public double weight(Vertex v1, Vertex v2) {
    return peso(v1, v2);
}

